  const adapterConfigDir = adapter?.getConfigDir();
  const effectiveConfigDir = adapterConfigDir ? resolveAgainst(projectDir, adapterConfigDir) : configDir || join4(homedir2(), ".claude");
  const adapterMemoryDir = adapter?.getMemoryDir();
  const memoryDir = adapterMemoryDir ? resolveAgainst(projectDir, adapterMemoryDir) : join4(effectiveConfigDir, "memory");
