    queries: exports_external.preprocess(coerceJsonArray, exports_external.array(exports_external.string()).min(1).describe("Search queries to extract information from indexed output. Use 5-8 comprehensive queries. Each returns top 5 matching sections with full content. " + "This is your ONLY chance — put ALL your questions here. No follow-up calls needed.")),
